class Solution:
    def waysToReachStair(self, k):
        count = 0
        max_ups = (k.bit_length() if k > 0 else 1) + 8
        max_pos = k + 4000
        def dfs(pos, jump, last_down, ups_used):
            nonlocal count
            if pos == k:
                count += 1
            if ups_used >= max_ups:
                return
            if pos > 0 and not last_down:
                dfs(pos - 1, jump, True, ups_used)
            newpos = pos + (1 << jump)
            if newpos <= max_pos:
                dfs(newpos, jump + 1, False, ups_used + 1)
        dfs(1, 0, False, 0)
        return count

