class Solution:
    def waysToReachStair(self, k):
        from math import comb
        total = 0
        t = 0
        while True:
            d = (1 << t) - k
            if d >= 0:
                if d > t + 1:
                    break
                total += comb(t + 1, d)
            t += 1
            if t > 100:
                break
        return total

