var waysToReachStair = function(k) {
    function comb(n, r) {
        if (r < 0 || r > n) return 0n;
        r = Math.min(r, n - r);
        let num = 1n, den = 1n;
        for (let i = 0; i < r; i++) {
            num *= BigInt(n - i);
            den *= BigInt(i + 1);
        }
        return num / den;
    }
    let total = 0n;
    let t = 0;
    while (true) {
        const d = (1 << t) - k;
        if (d >= 0) {
            if (d > t + 1) break;
            total += comb(t + 1, d);
        }
        t += 1;
        if (t > 100) break;
    }
    return Number(total);
};
